import ws from 'ws';
import { neonConfig } from '@neondatabase/serverless';
neonConfig.webSocketConstructor = ws;

database_access_via_context.example:
const resolvers = {
  Query: {
    users: async (_, __, { db }) => {
      return await db.select().from(usersTable);
    }
  }
};

api_patterns.schema_definition:
type Query {
  fieldName: ReturnType
}

type Mutation {
  mutationName(arg: InputType): ReturnType
}

code_structure.db_module:
// db.ts
import { drizzle } from 'drizzle-orm/neon-http';
import { neon } from '@neondatabase/serverless';

const sql = neon(process.env.DATABASE_URL!);
export const db = drizzle({ client: sql });

code_structure.apollo_setup:
// server.ts
import { ApolloServer } from '@apollo/server';
import { startStandaloneServer } from '@apollo/server/standalone';
import { db } from './db';

const server = new ApolloServer({ typeDefs, resolvers });
const { url } = await startStandaloneServer(server, {
  context: async () => ({ db })
});

code_structure.resolver_example:
// resolvers.ts
const resolvers = {
  Query: {
    brands: async (_, __, { db }) => {
      return await db.select().from(brandsTable);
    }
  },
  Mutation: {
    createBrand: async (_, { input }, { db }) => {
      const [brand] = await db.insert(brandsTable)
        .values(input)
        .returning();
      return brand;
    }
  }
};

error_handling.pattern:
try {
  const result = await db.select().from(table);
  return result;
} catch (error) {
  throw new GraphQLError('Failed to fetch data', {
    extensions: { code: 'DATABASE_ERROR' }
  });
}
